<template>
	<view class="container">
		<view class="header">
			<text class="title">设备管理</text>
		</view>
		
		<view class="equipment-stats">
			<view class="stat-item">
				<text class="stat-value">{{ totalDevices }}</text>
				<text class="stat-label">设备总数</text>
			</view>
			<view class="stat-item">
				<text class="stat-value">{{ runningDevices }}</text>
				<text class="stat-label">运行中</text>
			</view>
			<view class="stat-item">
				<text class="stat-value">{{ idleDevices }}</text>
				<text class="stat-label">空闲</text>
			</view>
			<view class="stat-item">
				<text class="stat-value">{{ maintenanceDevices }}</text>
				<text class="stat-label">维护中</text>
			</view>
		</view>
		
		<view class="equipment-section">
			<view class="section-header">
				<text class="section-title">设备列表</text>
				<text class="more">查看全部</text>
			</view>
			
			<view class="equipment-list">
				<view class="equipment-item" v-for="(device, index) in devices" :key="index">
					<view class="device-header">
						<view class="device-info">
							<text class="device-name">{{ device.name }}</text>
							<text class="device-code">{{ device.code }}</text>
						</view>
						<text class="device-status" :class="device.status">{{ device.statusText }}</text>
					</view>
					
					<view class="device-details">
						<text class="detail-item">型号：{{ device.model }}</text>
						<text class="detail-item">位置：{{ device.location }}</text>
						<text class="detail-item">运行时长：{{ device.runTime }} 小时</text>
					</view>
					
					<view class="device-actions">
						<button class="action-btn view" @click="viewDevice(device.id)">查看详情</button>
						<button class="action-btn maintain" @click="maintainDevice(device.id)">维护</button>
					</view>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
export default {
	data() {
		return {
			totalDevices: 24,
			runningDevices: 20,
			idleDevices: 2,
			maintenanceDevices: 2,
			devices: [
				{
					id: 'E001',
					name: '注塑机1',
					code: 'SZJ-001',
					model: 'Model-A',
					location: '车间1',
					runTime: 1245,
					status: 'running',
					statusText: '运行中'
				},
				{
					id: 'E002',
					name: '注塑机2',
					code: 'SZJ-002',
					model: 'Model-A',
					location: '车间1',
					runTime: 987,
					status: 'running',
					statusText: '运行中'
				},
				{
					id: 'E003',
					name: '包装机1',
					code: 'BZJ-001',
					model: 'Model-B',
					location: '车间2',
					runTime: 756,
					status: 'idle',
					statusText: '空闲'
				},
				{
					id: 'E004',
					name: '检测机1',
					code: 'JCJ-001',
					model: 'Model-C',
					location: '质检室',
					runTime: 1567,
					status: 'maintenance',
					statusText: '维护中'
				}
			]
		};
	},
	methods: {
		viewDevice(id) {
			uni.showToast({
				title: `查看设备#${id}`,
				icon: 'none'
			});
		},
		maintainDevice(id) {
			uni.showToast({
				title: `维护设备#${id}`,
				icon: 'none'
			});
		}
	}
};
</script>

